import pytest
import requests

BASE_URL = "http://localhost:8080/fhir"

@pytest.fixture
def clinician_headers():
    return <fixture:clinician_auth_headers>

@pytest.fixture
def existing_observation_id(clinician_headers):
    return <fixture:create_observation_and_return_id>(clinician_headers)

def test_post_diagnostic_report_valid_observation_links(
    clinician_headers, existing_observation_id
):
    payload = {
        "resourceType": "DiagnosticReport",
        "status": "final",
        "code": {"coding": [{"system": "http://loinc.org", "code": "58410-2"}]},
        "subject": {"reference": "Patient/example"},
        "result": [{"reference": f"Observation/{existing_observation_id}"}]
    }
    resp = requests.post(
        f"{BASE_URL}/DiagnosticReport",
        json=payload,
        headers=clinician_headers
    )
    assert resp.status_code == 201
    body = resp.json()
    assert "id" in body
    assert body.get("resourceType") == "DiagnosticReport"

import pytest
import requests

BASE_URL = "http://localhost:8080/fhir"

@pytest.fixture
def clinician_headers():
    return <fixture:clinician_auth_headers>

def test_post_diagnostic_report_missing_result_key_rejected(clinician_headers):
    payload = {
        "resourceType": "DiagnosticReport",
        "status": "final",
        "code": {"coding": [{"system": "http://loinc.org", "code": "58410-2"}]},
        "subject": {"reference": "Patient/example"}
    }
    resp = requests.post(
        f"{BASE_URL}/DiagnosticReport",
        json=payload,
        headers=clinician_headers
    )
    assert resp.status_code == 422
    body = resp.json()
    error_text = str(body).lower()
    assert "result" in error_text or "observation" in error_text
